{
  "terms": [
    {
      "term": "Statutory Regulations",
      "simpleDefinition": "Legally binding laws passed by Parliament that must be followed to avoid criminal prosecution.",
      "anchor": "Statutory equals Law.",
      "misconception": "Thinking statutory regulations are just 'best practice' suggestions rather than legal mandates."
    },
    {
      "term": "Non-statutory Regulations",
      "simpleDefinition": "Industry guidance and technical standards that describe how to work safely and meet legal requirements.",
      "anchor": "Non-statutory is Guidance.",
      "misconception": "Assuming non-statutory means 'optional' in a professional electrical context."
    },
    {
      "term": "BS 7671",
      "simpleDefinition": "The IET Wiring Regulations; the main non-statutory technical standard for UK electrical installations.",
      "anchor": "The Wiring Regs.",
      "misconception": "Believing BS 7671 is a statutory law (it is actually non-statutory guidance)."
    },
    {
      "term": "EAWR (Electricity at Work Regulations)",
      "simpleDefinition": "The primary statutory law that sets out legal duties for electrical safety in the workplace.",
      "anchor": "The legal rulebook for sparks.",
      "misconception": "Confusing the EAWR (the law) with BS 7671 (the technical guidance)."
    },
    {
      "term": "HASAWA (Health and Safety at Work Act)",
      "simpleDefinition": "The main statutory 'umbrella' law covering all health and safety in UK workplaces.",
      "anchor": "The foundation of all safety law.",
      "misconception": "Thinking HASAWA only applies to construction sites rather than every workplace."
    },
    {
      "term": "On-Site Guide",
      "simpleDefinition": "A non-statutory handbook that provides a simplified version of BS 7671 for common installation tasks.",
      "anchor": "The pocket-sized guide.",
      "misconception": "Thinking the On-Site Guide replaces the full BS 7671 requirements."
    },
    {
      "term": "Codes of Practice",
      "simpleDefinition": "Non-statutory documents that provide practical instructions on how to comply with specific legal duties.",
      "anchor": "The 'how-to' for compliance.",
      "misconception": "Believing that following a Code of Practice is the only way to comply with the law."
    },
    {
      "term": "PPE Regulations",
      "simpleDefinition": "Statutory laws requiring employers to provide and workers to use Personal Protective Equipment.",
      "anchor": "The law on safety gear.",
      "misconception": "Thinking PPE is a choice rather than a legal requirement when risks are present."
    }
  ],
  "anchorPhrases": [
    "Statutory equals Law.",
    "Non-statutory is Guidance.",
    "BS 7671 is the standard, not the law.",
    "EAWR is the law you must follow.",
    "Guidance helps you prove you followed the law."
  ],
  "misconceptionTargets": [
    "Believing BS 7671 is a statutory law.",
    "Assuming non-statutory guidance can be ignored without risk.",
    "Confusing technical manuals with actual Acts of Parliament.",
    "Thinking statutory regulations are just suggestions."
  ]
}

{
  "teachChecks": [
    {
      "title": "Statutory Regulations",
      "objective": "Identify the primary statutory regulations governing electrical work.",
      "retrievalTextLines": [
        "In the UK electrical industry, Statutory Regulations are the law. These are Acts of Parliament, and following them is a legal mandate, not a suggestion. If you break these rules, you are breaking the law, which can lead to criminal prosecution. The foundation of all workplace safety is the Health and Safety at Work Act (HASAWA). Under this umbrella act, we have specific regulations like the Electricity at Work Regulations (EAWR), which is the primary legal rulebook for sparks.",
        "Other essential statutory regulations you must recognize include the Electricity Safety, Quality and Continuity Regulations (ESQCR) and the Provision and Use of Work Equipment Regulations (PUWER). You also need to be aware of the Control of Substances Hazardous to Health (COSHH), Construction Design and Management (CDM), and the PPE Regulations. Even broader laws like the Environmental Act, the Disability Discrimination Act (DDA), and Equal Opportunities fall into this statutory category. Remember: Statutory equals Law. If it is an Act or a Regulation passed by Parliament, it is a mandatory legal requirement."
      ],
      "hint": "Focus on the fact that statutory documents are Acts of Parliament and carry the weight of law."
    },
    {
      "title": "Non-statutory Regulations and Guidance",
      "objective": "Identify non-statutory regulations and guidance documents used in the industry.",
      "retrievalTextLines": [
        "While statutory regulations are the law, Non-statutory Regulations are the industry guidance and technical standards that show you how to meet those laws. The most famous example is BS 7671, also known as the IET Wiring Regulations. A common misconception is that BS 7671 is a law; it is actually a non-statutory technical standard. However, following it is the best way to prove you have complied with statutory laws like the EAWR.",
        "Other non-statutory documents include the On-Site Guide, which is a simplified, pocket-sized version of the wiring regs for common tasks. You will also use Guidance Notes, the Unite Union Book, and various Codes of Practice. These documents provide the practical how-to for compliance. Although they are not laws themselves, they are rarely optional in a professional context. If something goes wrong and you have not followed these standards, it becomes very difficult to prove in court that you worked safely. Think of non-statutory documents as the professional roadmap to staying on the right side of the law."
      ],
      "hint": "Remember that BS 7671 and the On-Site Guide are technical standards, not laws passed by Parliament."
    }
  ]
}

